#!/usr/bin/env python3
"""Activity UI: clickable cards, modal popup, calendar legend, side-by-side columns"""
import base64, os, sys
if not os.path.exists("frontend/src/pages"):
    print("Error: Run from ~/seller-portal"); sys.exit(1)
content = base64.b64decode("")
with open("frontend/src/pages/ClientDashboard.jsx", "wb") as f:
    f.write(content)
print(f"  Updated: ClientDashboard.jsx ({len(content):,} bytes)")
print("\nNow run:")
print('  git add -A && git commit -m "Activity UI: modal popups, calendar legend, side-by-side cards" && git push')
